    % Callbacks that handle component events
    methods (Access = private)

        % Button pushed function: btnCLEAR
        function btnCLEARButtonPushed(app, event)
            app.edtIyy='';
            app.edttHEIGHT2.Value='';
            app.edtHEIGHT1.Value='';
            app.edtbaseL2.Value='';
           app.edtbaseL1.Value=''; 
        end

        % Button pushed function: btnButton2
        function btnButton2Pushed(app, event)

            HEIGHT2=app.edttHEIGHT2.Value;
            HEIGHT1=app.edtHEIGHT1.Value;
            baseL2 = app.edtbaseL2.Value;
            baseL1=app.edtbaseL1.Value;
            app.edtRANDOMdivisor.Value=12;
            app.edtAREA1.Value= HEIGHT1*baseL1;
            app.edtAREA2.Value=HEIGHT2*baseL2;
            app.edtCENTROID.Value=(((app.edtAREA1.Value*(HEIGHT1)/2)+(app.edtAREA2.Value*((HEIGHT2)/2+HEIGHT1))))/( app.edtAREA1.Value +app.edtAREA2.Value);
            app.edtMOMENT2.Value=((baseL2*(HEIGHT2)^3)/( app.edtRANDOMdivisor.Value))+(app.edtAREA2.Value)*((HEIGHT1+ (HEIGHT2)/2 - app.edtCENTROID.Value))^2;
            app.edtMOMENT1.Value=((baseL1*(HEIGHT1)^3)/( app.edtRANDOMdivisor.Value))+( app.edtAREA1.Value)*( app.edtCENTROID.Value-(app.edtHEIGHT1.Value/2))^2;
            app.edtIxx.Value=app.edtMOMENT2.Value + app.edtMOMENT1.Value;
            app.edtIyy.Value=((baseL1^3)*(HEIGHT1)/(app.edtRANDOMdivisor.Value))+( baseL2^3)*( HEIGHT2)/(app.edtRANDOMdivisor.Value);
        end

        % Button pushed function: btnButton
        function btnButtonPushed(app, event)
            app.edtIxx.Value='';
            app.edtMOMENT2.Value='';
            app.edtMOMENT1.Value='';
            app.edttHEIGHT2.Value='';
            app.edtHEIGHT1.Value='';
            app.edtbaseL2.Value='';
            app.edtbaseL1.Value=''; 
            app.edtCENTROID.Value='';
            app.edtAREA2.Value='';
            app.edtAREA1.Value='';
            app.edtIyy='';
        end
    end

